import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public List<List<String>> highestPopularity(String[] creators, String[] ids, int[] views) {
    Map<String, Integer> popularity = new HashMap<>();
    Map<String, Map.Entry<String, Integer>> mostViewed = new HashMap<>();

    for (int i = 0; i < creators.length; i++) {
        popularity.put(creators[i], popularity.getOrDefault(creators[i], 0) + views[i]);
        if (!mostViewed.containsKey(creators[i]) || views[i] > mostViewed.get(creators[i]).getValue()
            || (views[i] == mostViewed.get(creators[i]).getValue() && ids[i].compareTo(mostViewed.get(creators[i]).getKey()) < 0))
        {
            mostViewed.put(creators[i], Map.entry(ids[i], views[i]));
        }
    }

    int maxPopularity = 0;
    for (int value : popularity.values()) maxPopularity = Math.max(maxPopularity, value);

    List<List<String>> result = new ArrayList<>();
    for (Map.Entry<String, Integer> entry : popularity.entrySet()) {
        if (entry.getValue() == maxPopularity) {
            result.add(List.of(entry.getKey(), mostViewed.get(entry.getKey()).getKey()));
        }
    }
    return result;
}
```

